// Some portions generated by Codex
package org.eclipse.rdf4j.http.client;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.util.concurrent.atomic.AtomicReference;

import org.junit.jupiter.api.Test;

class QueryTraceRequestContextTest {

	@Test
	void activateShouldExposeAndRestoreNestedContexts() throws Exception {
		assertThat(QueryTraceRequestContext.getTraceRequestId()).isNull();

		try (QueryTraceRequestContext.Activation outer = QueryTraceRequestContext.activate("req-outer")) {
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-outer");

			try (QueryTraceRequestContext.Activation inner = QueryTraceRequestContext.activate("req-inner")) {
				assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-inner");
			}

			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-outer");
		}

		assertThat(QueryTraceRequestContext.getTraceRequestId()).isNull();
	}

	@Test
	void outOfOrderCloseShouldNotClobberCurrentContext() throws Exception {
		QueryTraceRequestContext.Activation outer = QueryTraceRequestContext.activate("req-outer");
		QueryTraceRequestContext.Activation inner = QueryTraceRequestContext.activate("req-inner");
		try {
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-inner");

			outer.close();
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-inner");

			inner.close();
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-outer");

			outer.close();
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isNull();
		} finally {
			inner.close();
			outer.close();
		}
	}

	@Test
	void activateShouldTrimTraceRequestIds() throws Exception {
		try (QueryTraceRequestContext.Activation ignored = QueryTraceRequestContext.activate("  req-trim  ")) {
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-trim");
		}
	}

	@Test
	void activateShouldRemainThreadLocal() throws Exception {
		AtomicReference<String> workerThreadTraceRequestId = new AtomicReference<>("missing");

		try (QueryTraceRequestContext.Activation ignored = QueryTraceRequestContext.activate("req-main")) {
			Thread worker = new Thread(
					() -> workerThreadTraceRequestId.set(QueryTraceRequestContext.getTraceRequestId()));
			worker.start();
			worker.join();

			assertThat(workerThreadTraceRequestId).hasValue(null);
			assertThat(QueryTraceRequestContext.getTraceRequestId()).isEqualTo("req-main");
		}

		assertThat(QueryTraceRequestContext.getTraceRequestId()).isNull();
	}

	@Test
	void activateShouldRejectNullAndBlankRequestIds() {
		assertThatThrownBy(() -> QueryTraceRequestContext.activate(null))
				.isInstanceOf(NullPointerException.class)
				.hasMessage("Trace request id was null");
		assertThatThrownBy(() -> QueryTraceRequestContext.activate("   "))
				.isInstanceOf(IllegalArgumentException.class)
				.hasMessage("Trace request id was blank");
	}
}
